const clamp=(t,e,n)=>Math.max(e,Math.min(t,n));function precisionRound(t,e=1){e=Math.pow(10,e);return Math.round(t*e)/e}function getDecimalPrecision(t){var e,n;return Math.abs(t)<1?((n=(e=t.toExponential().split("e-"))[0].split(".")[1])?n.length:0)+parseInt(e[1],10):(n=t.toString().split(".")[1])?n.length:0}function roundValueToStep(t,e,n){t=Math.round((t-n)/e)*e+n;return Number(t.toFixed(getDecimalPrecision(e)))}function decimatedClamp(t,e,n,r){return null==r||r<=0||(t=roundValueToStep(t,r,e)),clamp(t,e,n)}function rescale(t,e,n,r={}){return decimatedClamp((t-e[0])/(e[1]-e[0])*(n[1]-n[0])+n[0],n[0],n[1],r.step)}export{clamp,precisionRound,rescale};